#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n; scanf("%d", &n);
        int *a = (int*)malloc(n*sizeof(int));
        for(int i=0;i<n;++i) scanf("%d", &a[i]);
        int target; scanf("%d", &target);
        // simple hash using linear probing could be written, but O(N^2) is acceptable for constraints.
        int idx1=-1, idx2=-1;
        for(int i=0;i<n && idx1==-1;++i){
            for(int j=i+1;j<n;++j){
                if(a[i]+a[j]==target){ idx1=i; idx2=j; break; }
            }
        }
        printf("%d %d\n", idx1, idx2);
        free(a);
    }
    return 0;
}

